-- Auto-generated: upgrades steps + ingredients for the curated recipes
-- already in public.recipes (the seed INSERT skips existing names).
-- Safe to re-run; only updates rows whose name matches. Run in Supabase SQL editor.

update public.recipes r
set steps = v.steps, ingredients = v.ingredients
from (values
    ('Paneer Tikka Masala', 'Heat 2 tbsp oil in a heavy pan; add 1 large finely chopped onion and saute 5-6 minutes until golden brown; Add 1 tbsp ginger-garlic paste and cook 1 minute until the raw smell disappears; Add 2 pureed tomatoes (or 3 tbsp tomato paste) and cook 4-5 minutes until the oil separates at the edges; Stir in 1/2 tsp turmeric, 1 tsp red chilli powder, 1 tsp coriander powder and 3/4 tsp salt; cook 1 minute; Add the paneer with about 3/4 cup water, cover and simmer 10-12 minutes until cooked through and the gravy thickens; Sprinkle 1/2 tsp garam masala, swirl in 2 tbsp cream or whisked yogurt, and finish with chopped coriander; serve hot', 'paneer, onion, tomato, ginger, garlic, cumin, turmeric, red chilli powder, coriander powder, garam masala, salt, oil, coriander leaves'),
